1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation, 1 neighbor each)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block alive unchanged (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    const sortCells = (cells: [number, number][]) =>
18	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
19	    expect(sortCells(result)).toEqual(sortCells(block));
20	  });
21	  it("should let a live cell with 2 or 3 neighbors survive (survival)", () => {
22	    // L-shape: (1,1) has 3 live neighbors (0,0),(1,0),(2,0) → survives
23	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1]];
24	    const result = nextGeneration(input);
25	    const sortCells = (cells: [number, number][]) =>
26	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
27	    // Expected next generation:
28	    // (1,1) alive, 3 neighbors → survives
29	    // (0,0) alive, 2 neighbors → survives
30	    // (1,0) alive, 3 neighbors → survives
31	    // (2,0) alive, 2 neighbors → survives
32	    // (0,1) dead, 3 neighbors → born
33	    // (2,1) dead, 3 neighbors → born
34	    // (1,-1) dead, 3 neighbors → born
35	    const expected: [number, number][] = [
36	      [0, 0], [1, 0], [2, 0], [0, 1], [1, 1], [2, 1], [1, -1],
37	    ];
38	    expect(sortCells(result)).toEqual(sortCells(expected));
39	  });
40	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
41	    // 3x3 filled block - center (1,1) has 8 neighbors → dies
42	    const input: [number, number][] = [
43	      [0, 0], [1, 0], [2, 0],
44	      [0, 1], [1, 1], [2, 1],
45	      [0, 2], [1, 2], [2, 2],
46	    ];
47	    const result = nextGeneration(input);
48	    const sortCells = (cells: [number, number][]) =>
49	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
50	    // Expected: corners survive, edges die (5 neighbors each), center dies (8 neighbors)
51	    // 4 dead cells outside the block come alive (3 neighbors each)
52	    const expected: [number, number][] = [
53	      [0, 0], [2, 0], [0, 2], [2, 2],
54	      [-1, 1], [3, 1], [1, -1], [1, 3],
55	    ];
56	    expect(sortCells(result)).toEqual(sortCells(expected));
57	  });
58	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
59	    // Gen 0: L-shape at top-left corner of 3x3 (y-up):
60	    //   row 2: ##.   → (0,2),(1,2)
61	    //   row 1: #..   → (0,1)
62	    //   row 0: ...
63	    const input: [number, number][] = [[0, 2], [1, 2], [0, 1]];
64	    const result = nextGeneration(input);
65	    const sortCells = (cells: [number, number][]) =>
66	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
67	    // Expected Gen 1: dead (1,1) has 3 live neighbors → born; the 3 live cells survive (2 neighbors each)
68	    const expected: [number, number][] = [[0, 2], [1, 2], [0, 1], [1, 1]];
69	    expect(sortCells(result)).toEqual(sortCells(expected));
70	  });
71	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
72	  it.todo("should handle negative coordinates");
73	});
